def write_jsonl(path: str, data: list):
    os.makedirs(os.path.dirname(path), exist_ok=True)
    with open(path, "w", encoding="utf-8") as f:
        for item in data:
            f.write(json.dumps(item, ensure_ascii=False) + "\n")
    print(f"Wrote {len(data)} examples to {path}")


if __name__ == "__main__":
    base_dir = os.path.dirname(os.path.dirname(os.path.abspath(__file__)))
    sft_dir = os.path.join(base_dir, "data", "sft")

    # Shuffle train pairs
    train_pairs = PAIRS.copy()
    random.shuffle(train_pairs)

    train_path = os.path.join(sft_dir, "yaya_dpo_train.jsonl")
    eval_path = os.path.join(sft_dir, "yaya_dpo_eval.jsonl")

    write_jsonl(train_path, train_pairs)
    write_jsonl(eval_path, EVAL_PAIRS)

    print(f"\nDPO dataset ready:")
    print(f"  Train: {len(train_pairs)} pairs")
    print(f"  Eval:  {len(EVAL_PAIRS)} pairs")
    print(f"\nNext step: python scripts/align_dpo_hf.py --model_path outputs/yaya-sft --data_dir data/sft")
